#!/bin/bash
# 创建简单的 PNG 占位图标（1x1 像素透明 PNG，实际开发中应替换为真实图标）
# 这里使用 base64 编码的简单 PNG

# home.png (灰色)
echo "" | base64 -d > home.png

# home-active.png (紫色)
echo "" | base64 -d > home-active.png

# projects.png (灰色)
echo "" | base64 -d > projects.png

# projects-active.png (紫色)  
echo "" | base64 -d > projects-active.png

# profile.png (灰色)
echo "" | base64 -d > profile.png

# profile-active.png (紫色)
echo "" | base64 -d > profile-active.png

echo "PNG icons created successfully!"
